import { VersicoEstudo } from './versiculosEstudoTypes';

const registro: Record<string, VersicoEstudo> = {};

function addVS(
  capitulo: number, v: number,
  titulo: string, contextoHistorico: string,
  contextoLiterario: string, significadoTeologico: string,
  aplicacoes: string[], perguntasEstudo: string[],
  versiculosConexoes: string[]
) {
  registro[`${capitulo}:${v}`] = {
    livro: 'gn', capitulo, versiculo: v, titulo,
    contextoHistorico, contextoLiterario, significadoTeologico,
    aplicacoes, perguntasEstudo, versiculosConexoes
  };
}

addVS(1, 1, "A criação dos céus e da terra (v. 1)", "Escrito por Moisés no deserto, relatando a origem do mundo, da humanidade e da nação de Israel, bem como as alianças patriarcais. Este capítulo situa-se no contexto geral de Gênesis.", "Narrativa histórica composta por genealogias, relatos de criação e ciclos patriarcais. O capítulo 1 desenvolve: A criação dos céus e da terra.", "Em Gênesis 1:1, destaca-se a criação dos céus e da terra. Deus como Criador soberano e fiel às Suas promessas, estabelecendo a aliança abraâmica que culmina em Cristo.", ["Aplicar a verdades de a criação dos céus e da terra na vida diária","Buscar a direção de Deus por meio deste texto","Viver em conformidade com a vontade revelada em Gênesis"], ["O que este versículo ensina sobre o caráter de Deus?","Como a criação dos céus e da terra se aplica à minha vida hoje?","Que conexão este texto tem com o restante das Escrituras?"], ["Jo 1:1","Hb 11:3","Rm 1:20"]);
